const ORIGIN = "https://assets.ricequant.com";
const PREFIX = ORIGIN + "/vendor/browser-upgrade";
const cssVer = "v0";

function isSupportedBrowser() {
  function hasProxy() {
    return typeof Proxy === "function" && /native code/.test(Proxy.toString());
  }

  function isCssVarSupported() {
    return (
      window.CSS &&
      window.CSS.supports &&
      window.CSS.supports("color", "var(--fake-var)")
    );
  }

  return !!(hasProxy() && isCssVarSupported());
}

